namespace InventoryApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A", Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B", Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 10) },
            new() { Id = 3, Name = "Drill Press C", Location = "Workshop", LastInspected = new DateTime(2026, 1, 22) },
            new() { Id = 4, Name = "Lathe D", Location = "Workshop", LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 5, Name = "Pallet Jack E", Location = "Warehouse 1", LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 6, Name = "Crane F", Location = "Yard", LastInspected = new DateTime(2026, 2, 28) },
            new() { Id = 7, Name = "Compressor G", Location = "Utility Room", LastInspected = new DateTime(2026, 4, 20) },
            new() { Id = 8, Name = "Welder H", Location = "Workshop", LastInspected = new DateTime(2026, 3, 3) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Models
@using InventoryApp.Services
@inject EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // Try to restore data persisted during prerender; if found, skip the service call.
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            items = restored;
        }
        else
        {
            items = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

